import React from "react";
import { NavLink, useNavigate } from "react-router-dom";
import "./Sidebar.css";

const Sidebar = () => {
  const navigate = useNavigate();

  let user = null;
  try {
    user = JSON.parse(localStorage.getItem("user"));
  } catch {
    user = null;
  }

  const handleLogout = () => {
    localStorage.clear();
    navigate("/login");
  };

  return (
    <div className="sidebar">
      <h3 className="sidebar-title">Menu</h3>

      <NavLink to="/profile" className="sidebar-link">
        Profile
      </NavLink>

      <NavLink to="/account" className="sidebar-link">
        Account
      </NavLink>

      {user?.role === "student" && (
        <>
          <NavLink to="/student/events" className="sidebar-link">
            Events
          </NavLink>
          <NavLink to="/student/my-events" className="sidebar-link">
            My Registrations
          </NavLink>
        </>
      )}

      {user?.role === "staff" && (
        <>
          <NavLink to="/staff/dashboard" className="sidebar-link">
            Dashboard
          </NavLink>
          <NavLink to="/staff/events" className="sidebar-link">
            Events
          </NavLink>
        </>
      )}

      {user?.role === "admin" && (
        <>
          <NavLink to="/admin/dashboard" className="sidebar-link">
            Dashboard
          </NavLink>
          <NavLink to="/admin/events" className="sidebar-link">
            Manage Events
          </NavLink>
          <NavLink to="/admin/users" className="sidebar-link">
            All Users
          </NavLink>
        </>
      )}

      <button className="logout-btn" onClick={handleLogout}>
        Logout
      </button>
    </div>
  );
};

export default Sidebar;
